"use client";

import { useEffect, useState } from "react";

/**
 * useSubnavPin — local preference for whether the dept subnav is pinned open.
 *
 * Default = UNPINNED (false). The subnav lives as a 24px trigger strip that
 * expands on hover and auto-opens briefly when entering a new dept. User
 * can pin it open from the pin button in the panel head.
 * Preference persists across sessions via localStorage.
 *
 * Note on SSR: on first render before hydration, this reports the default
 * (unpinned). On mount it reads localStorage and updates if the user had
 * pinned it. There may be a one-frame flash before settling — acceptable
 * trade-off vs. SSR complications.
 */

const KEY = "magellan:subnav-pinned";

export function useSubnavPin(): [boolean, (v: boolean) => void] {
  const [pinned, setPinnedState] = useState(false);

  useEffect(() => {
    try {
      const stored = window.localStorage.getItem(KEY);
      if (stored !== null) setPinnedState(stored === "true");
    } catch {
      /* localStorage unavailable — keep default */
    }
  }, []);

  const setPinned = (v: boolean) => {
    setPinnedState(v);
    try {
      window.localStorage.setItem(KEY, String(v));
    } catch {
      /* no-op */
    }
  };

  return [pinned, setPinned];
}
