"use client";

/* ════════════════════════════════════════════════════════════════════════
   useBridge — router-backed Bridge navigation.

   The Bridge is now ROUTE-BASED (not a global overlay): each surface is a
   real, deep-linkable, code-split page under /bridge/[dept]/[surface].
   This hook keeps the OLD api (dept / page / openBridge / setPage / setDept /
   closeBridge) so the surface components don't need rewriting — but every
   call now navigates instead of mutating context state.

     openBridge("finance", "classify")  → router.push("/bridge/finance/classify")
     setPage("home")                    → router.push("/bridge/finance")
     closeBridge()                      → router.push("/finance")   (the room)

   Deep-link from analytics: a button is just a <Link> (or openBridge) to the
   exact surface URL, optionally carrying the entity (?id=…). Next.js code-
   splits each surface route, so only the clicked surface's JS loads.
   ════════════════════════════════════════════════════════════════════════ */

import { useRouter, usePathname, useParams } from "next/navigation";
import { useCallback } from "react";

export type BridgeDept = "ops" | "growth" | "finance" | "customers";

/** Which surface inside the Bridge — the [surface] route slug.
 *  "home" = the dept Bridge home (/bridge/[dept]). */
export type BridgePage =
  | "home"
  // Operations
  | "new-item"
  | "reorder"
  | "hold"
  | "watch"
  | "liquidate"
  | "stock-adjustment"
  | "replenishment-plan"
  | "rebalance"
  | "add-category"
  | "add-supplier"
  | "diversify-supplier"
  | "adjust-supplier"
  | "approve-po"
  | "escalate-po"
  | "receive"
  | "update-costs"
  | "capture-receipt"
  | "produce"
  | "return"
  | "packaging-review"
  // Finance
  | "log-entry"
  | "recurring-cost"
  | "classify"
  | "approve-payment"
  | "reconcile"
  | "close-month";

const DEPTS: BridgeDept[] = ["ops", "growth", "finance", "customers"];

function isDept(v: unknown): v is BridgeDept {
  return typeof v === "string" && (DEPTS as string[]).includes(v);
}

const surfaceHref = (dept: BridgeDept, page: BridgePage) =>
  page === "home" ? `/bridge/${dept}` : `/bridge/${dept}/${page}`;

export function useBridge() {
  const router = useRouter();
  const pathname = usePathname();
  const params = useParams();

  // dept / surface come from the URL. On a non-bridge route params is empty,
  // so dept falls back to "ops" — callers that matter (AIStrip) pass it explicitly.
  const dept: BridgeDept = isDept(params?.dept) ? (params.dept as BridgeDept) : "ops";
  const page = ((params?.surface as string | undefined) ?? "home") as BridgePage;
  const open = pathname?.startsWith("/bridge") ?? false;

  const openBridge = useCallback(
    (d?: BridgeDept, p?: BridgePage) => {
      const dd = d ?? dept;
      router.push(surfaceHref(dd, p ?? "home"));
    },
    [router, dept]
  );

  const setPage = useCallback(
    (p: BridgePage) => router.push(surfaceHref(dept, p)),
    [router, dept]
  );

  const setDept = useCallback(
    (d: BridgeDept) => router.push(`/bridge/${d}`),
    [router]
  );

  // Close = back to the dept's analytics room (dept slug == room path).
  const closeBridge = useCallback(() => router.push(`/${dept}`), [router, dept]);

  return { open, dept, page, openBridge, closeBridge, setPage, setDept };
}

/** Back-compat passthrough — the old global provider is no longer needed
 *  (state lives in the URL now). Kept so existing imports don't break. */
export function BridgeProvider({ children }: { children: React.ReactNode }) {
  return children;
}
